# ── SMTP CONFIG ─────────────────────────────────────────────────
# Priority: environment variable → secrets.toml → hardcoded fallback
def _get(key, default=""):
    # 1. Check environment variable
    val = os.getenv(key, "")
    if val: return val
    # 2. Check Streamlit secrets
    try:
        return st.secrets.get(key, default)
    except:
        return default

SMTP_HOST     = _get("SMTP_HOST",     "smtp.gmail.com")
SMTP_PORT     = int(_get("SMTP_PORT", "587"))
SMTP_USER     = _get("SMTP_USER",     "phagnariya@gmail.com")   # ← PUT YOUR GMAIL HERE if not using .env
SMTP_PASSWORD = _get("SMTP_PASSWORD","ydakfzfgleutdqsn")   # ← PUT YOUR APP PASSWORD HERE
SMTP_FROM     = _get("SMTP_FROM",     "phagnariya@gmail.com")

def send_email_otp(to_email: str, otp: str):
    """Send OTP email via SMTP. Returns (True, "") or (False, error_msg)."""
    if not SMTP_USER or not SMTP_PASSWORD:
        return False, "SMTP_NOT_CONFIGURED"
    try:
        msg = MIMEMultipart("alternative")
        msg["Subject"] = "HealNet — Your OTP Code"
        msg["From"]    = f"HealNet <{SMTP_FROM}>"
        msg["To"]      = to_email
        html = f"""
        <div style="font-family:Arial,sans-serif;max-width:480px;margin:auto;
                    background:#030c2c;border-radius:16px;padding:32px;color:#fff;">
          <h2 style="color:#3BC9E8;margin:0 0 6px;">🔐 HealNet</h2>
          <p style="color:rgba(255,255,255,0.6);font-size:12px;margin:0 0 24px;">
             PREDICT. PREVENT. PERSONALIZE.</p>
          <p style="font-size:16px;font-weight:600;margin:0 0 12px;color:#fff;">
             Your One-Time Password (OTP):</p>
          <div style="background:#04163c;border:2px solid #3BC9E8;border-radius:12px;
                      padding:24px;text-align:center;letter-spacing:.4em;
                      font-size:38px;font-weight:800;color:#3BC9E8;margin:0 0 20px;">
            {otp}
          </div>
          <p style="color:rgba(255,255,255,0.7);font-size:14px;margin:0 0 6px;">
            ⏱ This OTP is valid for <strong>5 minutes only</strong>.</p>
          <p style="color:rgba(255,255,255,0.4);font-size:12px;margin:0;">
            If you did not request this, please ignore this email.</p>
          <hr style="border:none;border-top:1px solid rgba(255,255,255,0.1);margin:24px 0 12px;">
          <p style="color:rgba(255,255,255,0.25);font-size:11px;text-align:center;margin:0;">
            A Product By IoTrenetics Solutions Pvt. Ltd.</p>
        </div>"""
        msg.attach(MIMEText(html, "html"))
        with smtplib.SMTP(SMTP_HOST, SMTP_PORT, timeout=10) as srv:
            srv.ehlo()
            srv.starttls()
            srv.ehlo()
            srv.login(SMTP_USER, SMTP_PASSWORD)
            srv.sendmail(SMTP_FROM, to_email, msg.as_string())
        return True, ""
    except smtplib.SMTPAuthenticationError:
        return False, "AUTH_ERROR"
    except smtplib.SMTPException as e:
        return False, f"SMTP_ERROR: {e}"
    except Exception as e:
        return False, f"ERROR: {e}"

