def screen_org():
    logo(); back_btn(); card_open()
    portal_header("#f0fdfa","Organisation Portal","Hospital · Clinic · Healthcare Facility")
    show_msg()
    t1,t2=st.tabs(["Sign In","Register Org"])
    with t1:
        st.markdown("<br>",unsafe_allow_html=True)
        u=st.text_input("Username",placeholder="admin",key="ol_u")
        p=st.text_input("Password",type="password",placeholder="••••••••",key="ol_p")
        st.markdown("<br>",unsafe_allow_html=True)
        if st.button("Sign In as Organisation",key="ol_btn",type="primary"):
            if not u or not p: alert("Please fill in all fields."); st.rerun()
            else:
                con=db(); row=con.execute("SELECT * FROM organisations WHERE username=? AND password=?",(u,hp(p))).fetchone(); con.close()
                if row: do_login("org",org=dict(row)); st.rerun()
                else:   alert("Invalid username or password."); st.rerun()
        st.markdown('<p style="text-align:center;margin-top:14px;font-size:14px;color:rgba(255,255,255,0.6);">Forgot your password?</p>', unsafe_allow_html=True)
        if st.button("🔑 Reset via OTP", key="fp_org", type="secondary"):
            go("forgot"); st.rerun()
    with t2:
        st.markdown("<br>",unsafe_allow_html=True)
        n=st.text_input("Organisation Name",placeholder="City General Hospital",key="or_n")
        re=st.text_input("Contact Email *",placeholder="admin@hospital.com",key="or_e")
        ru=st.text_input("Username",placeholder="admin",key="or_u")
        rp=st.text_input("Password",type="password",placeholder="••••••••",key="or_p")
        rp2=st.text_input("Confirm Password",type="password",placeholder="••••••••",key="or_p2")
        st.markdown("<br>",unsafe_allow_html=True)
        if st.button("Register Organisation",key="or_btn",type="primary"):
            if not n:              alert("⚠️ Organisation name is required."); st.rerun()
            elif not re:           alert("⚠️ Contact email is required."); st.rerun()
            elif "@" not in re:    alert("⚠️ Enter a valid email."); st.rerun()
            elif not ru:           alert("⚠️ Username is required."); st.rerun()
            elif not rp:           alert("⚠️ Password is required."); st.rerun()
            elif not rp2:          alert("⚠️ Please confirm your password."); st.rerun()
            elif rp!=rp2:          alert("⚠️ Passwords do not match."); st.rerun()
            elif len(rp)<6:        alert("⚠️ Password must be at least 6 characters."); st.rerun()
            else:
                con=db()
                try:
                    code=gen_code()
                    con.execute("INSERT INTO organisations(name,username,password,org_code,email) VALUES(?,?,?,?,?)",(n,ru,hp(rp),code,re)); con.commit()
                    alert(f"✅ Registered! Org Code: {code} — share this with your staff and patients.","success")
                except sqlite3.IntegrityError: alert("⚠️ Username already exists. Try another.")
                finally: con.close()
                st.rerun()
    card_close(); footer()


