# SCREEN: ORGANISATION
# ════════════════════════════════════════════════════════════════
def screen_org():
    card_open()
    back_btn()
    portal_header("#f0fdfa", "#ccfbf1", "Organisation Portal", "Hospital · Clinic · Healthcare Facility")
    show_msg()
    t1, t2 = st.tabs(["Sign In", "Register"])
    with t1:
        st.markdown("<br>", unsafe_allow_html=True)
        u = st.text_input("Username", placeholder="admin", key="ol_u")
        p = st.text_input("Password", type="password", placeholder="••••••••", key="ol_p")
        st.markdown("<br>", unsafe_allow_html=True)
        if st.button("Sign In", key="ol_btn", type="primary"):
            if not u or not p:
                alert("Please fill in all fields."); st.rerun()
            else:
                con = db()
                row = con.execute("SELECT * FROM organisations WHERE username=? AND password=?", (u, hp(p))).fetchone()
                con.close()
                if row: do_login("org", org=dict(row)); st.rerun()
                else: alert("Invalid username or password."); st.rerun()
    with t2:
        st.markdown("<br>", unsafe_allow_html=True)
        n   = st.text_input("Organisation Name", placeholder="City General Hospital", key="or_n")
        ru  = st.text_input("Username", placeholder="admin", key="or_u")
        rp  = st.text_input("Password", type="password", placeholder="••••••••", key="or_p")
        rp2 = st.text_input("Confirm Password", type="password", placeholder="••••••••", key="or_p2")
        st.markdown("<br>", unsafe_allow_html=True)
        if st.button("Register Organisation", key="or_btn", type="primary"):
            if not all([n, ru, rp, rp2]): alert("All fields are required."); st.rerun()
            elif rp != rp2: alert("Passwords do not match."); st.rerun()
            elif len(rp) < 6: alert("Password must be at least 6 characters."); st.rerun()
            else:
                con = db()
                try:
                    code = gen_code()
                    con.execute("INSERT INTO organisations(name,username,password,org_code) VALUES(?,?,?,?)", (n, ru, hp(rp), code))
                    con.commit()
                    alert(f"Registered successfully. Organisation Code: {code}", "success")
                except sqlite3.IntegrityError: alert("Username already exists.")
                finally: con.close()
                st.rerun()
    st.markdown('<hr style="border:none;border-top:1px solid rgba(255,255,255,0.12);margin:18px 0 10px;">', unsafe_allow_html=True)
    st.markdown('<p style="text-align:center;font-size:14px;color:rgba(255,255,255,0.55);margin-bottom:8px;">Forgot your password?</p>', unsafe_allow_html=True)
    if st.button("🔑 Reset Password via OTP", key="fp_org2"):
        go("forgot"); st.rerun()
    card_close()


