# SCREEN: OTP VERIFY — Step 2: Enter 6-digit OTP
# ════════════════════════════════════════════════════════════════
def screen_otp_verify():
    card_logo(); card_open()
    st.markdown('<div class="card-title" style="font-size:22px;color:#fff;font-weight:700;margin-bottom:4px;">🔐 Verify OTP</div>', unsafe_allow_html=True)
    masked = mask_email(st.session_state.get("otp_email",""))
    st.markdown(f'<div class="card-sub" style="font-size:15px;color:rgba(255,255,255,0.85);margin-bottom:6px;">A 6-digit OTP was sent to <strong style="color:#3BC9E8;">{masked}</strong></div>', unsafe_allow_html=True)

    # Live countdown
    expiry = st.session_state.get("otp_expiry", 0)
    remaining = max(0, int(expiry - time.time()))
    mins, secs = divmod(remaining, 60)
    color = "#00C9A7" if remaining > 60 else "#ef4444"
    st.markdown(f'<div style="font-size:14px;color:{color};font-weight:700;margin-bottom:18px;">⏱ Expires in: {mins}:{secs:02d}</div>', unsafe_allow_html=True)

    show_msg()
    otp_entered = st.text_input("Enter 6-Digit OTP", placeholder="e.g. 482910", max_chars=6, key="otp_input")
    st.markdown("<br>", unsafe_allow_html=True)
    col1, col2 = st.columns(2)
    with col1:
        if st.button("← Back", key="otp_back", type="secondary"):
            go("forgot"); st.rerun()
    with col2:
        if st.button("Verify OTP ✓", key="otp_verify_btn", type="primary"):
            if not otp_entered:
                alert("⚠️ Please enter the OTP."); st.rerun()
            else:
                valid, msg = otp_valid(otp_entered)
                if valid:
                    go("reset_password"); st.rerun()
                else:
                    alert(f"⚠️ {msg}"); st.rerun()
    st.markdown("<br>", unsafe_allow_html=True)
    if st.button("↺ Resend OTP", key="otp_resend", type="secondary"):
        send_otp(st.session_state.otp_user_type, st.session_state.otp_target)
        st.rerun()
    card_close()


